+    version: 2,
     payload: payload.toString("base64url"),
-    signature: sign("RSA-SHA256", payload, keys.rsaPrivateKey).toString("base64url")
+    signature: sign(null, payload, { key: keys.mlDsaPrivateKey, context: Buffer.from(context) }).toString("base64url")
